{"content":"import React, { useState } from 'react';
import { Mail, Lock, ArrowRight, Loader2, Github, AlertCircle, User as UserIcon, X, CheckCircle2 } from 'lucide-react';
import { User } from '../types';

interface LoginProps {
  onLogin: (user: User) => void;
  onBack: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onBack }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [socialProvider, setSocialProvider] = useState<'google' | 'github' | null>(null);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  // --- Handlers ---

  const initSocialLogin = (provider: 'google' | 'github') => {
    setSocialProvider(provider);
    setIsLoading(false);
  };

  const finalizeSocialLogin = async (provider: 'google' | 'github') => {
    setIsLoading(true);
    // Simulation délai réseau OAuth
    await new Promise(resolve => setTimeout(resolve, 1500));

    const mockUser: User = {
      id: `${provider}_${Math.random().toString(36).substr(2, 9)}`,
      name: provider === 'google' ? 'Utilisateur Google' : 'Développeur GitHub',
      email: provider === 'google' ? 'user@gmail.com' : 'dev@github.com',
      plan: 'free',
      credits: 0 // Pas de crédit gratuit
    };

    onLogin(mockUser);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    // Simulation d'appel API
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Validation simple
    if (!email || password.length < 4) {
      setError('Identifiants invalides. Le mot de passe doit contenir au moins 4 caractères.');
      setIsLoading(false);
      return;
    }

    if (isRegistering) {
        if (password !== confirmPassword) {
            setError("Les mots de passe ne correspondent pas.");
            setIsLoading(false);
            return;
        }
        if (!name) {
            setError("Veuillez renseigner votre nom.");
            setIsLoading(false);
            return;
        }
    }

    // Success Simulation
    const mockUser: User = {
      id: 'user_' + Math.random().toString(36).substr(2, 9),
      name: isRegistering ? name : email.split('@')[0],
      email: email,
      plan: 'free',
      credits: 0 // Pas de crédit gratuit, même à l'inscription
    };

    onLogin(mockUser);
  };

  const toggleMode = () => {
      setIsRegistering(!isRegistering);
      setError('');
      setPassword('');
      setConfirmPassword('');
  };

  // --- MOCK GOOGLE LOGIN VIEW ---
  if (socialProvider === 'google') {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center font-sans text-gray-800 animate-in fade-in zoom-in duration-300">
        <div className="w-full max-w-[450px] p-8 md:border md:border-gray-200 md:rounded-lg md:shadow-sm bg-white">
          <div className="flex justify-center mb-4">
             <svg viewBox="0 0 24 24" className="w-10 h-10">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
             </svg>
          </div>
          <h2 className="text-2xl font-medium text-center mb-2 text-gray-900">Connexion</h2>
          <p className="text-center text-gray-600 mb-8">Utiliser votre compte Google</p>

          <div className="space-y-6">
             <div className="relative group">
                <input 
                  type="email" 
                  className="peer w-full border border-gray-300 rounded px-3 py-3.5 text-gray-900 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none transition-colors"
                  value="user@gmail.com" 
                  readOnly
                />
                <label className="absolute left-3 top-[-10px] bg-white px-1 text-xs text-blue-600 font-medium">Adresse e-mail</label>
             </div>

             <div className="text-sm text-blue-600 font-medium cursor-pointer hover:text-blue-700">
               Adresse e-mail oubliée ?
             </div>

             <div className="text-sm text-gray-600">
                Ce n'est pas votre ordinateur ? Utilisez le mode Invité pour vous connecter en privé. <span className="text-blue-600 font-medium cursor-pointer">En savoir plus</span>
             </div>

             <div className="flex justify-between items-center pt-8">
                <button 
                  onClick={() => setSocialProvider(null)}
                  className="text-blue-600 font-medium hover:bg-blue-50 px-4 py-2 rounded transition-colors"
                >
                  Créer un compte
                </button>
                <button 
                   onClick={() => finalizeSocialLogin('google')}
                   disabled={isLoading}
                   className="bg-[#1a73e8] text-white font-medium px-6 py-2 rounded hover:bg-blue-700 transition-colors shadow-sm min-w-[100px] flex justify-center"
                >
                   {isLoading ? <Loader2 size={20} className="animate-spin" /> : 'Suivant'}
                </button>
             </div>
          </div>
        </div>
        <div className="fixed bottom-4 left-4 text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded border border-gray-300">
           Mode Simulation OAuth
        </div>
      </div>
    );
  }

  // --- MOCK GITHUB LOGIN VIEW ---
  if (socialProvider === 'github') {
    return (
      <div className="min-h-screen bg-[#0d1117] flex flex-col items-center pt-12 font-sans text-gray-100 animate-in fade-in zoom-in duration-300">
         <div className="mb-8">
            <Github size={48} className="text-white" />
         </div>
         <h2 className="text-xl font-light mb-4">Sign in to GitHub</h2>

         <div className="w-full max-w-[340px] bg-[#161b22] border border-[#30363d] rounded-lg p-5">
            <div className="space-y-4">
               <div>
                  <label className="block text-sm mb-2 font-medium">Username or email address</label>
                  <input 
                     type="text" 
                     className="w-full bg-[#0d1117] border border-[#30363d] rounded-md px-3 py-1.5 text-white focus:border-blue-500 focus:ring-2 focus:ring-blue-500/40 outline-none transition-all"
                     autoFocus
                  />
               </div>
               <div>
                  <div className="flex justify-between mb-2">
                     <label className="block text-sm font-medium">Password</label>
                     <span className="text-xs text-blue-400 hover:underline cursor-pointer">Forgot password?</span>
                  </div>
                  <input 
                     type="password" 
                     className="w-full bg-[#0d1117] border border-[#30363d] rounded-md px-3 py-1.5 text-white focus:border-blue-500 focus:ring-2 focus:ring-blue-500/40 outline-none transition-all"
                  />
               </div>

               <button 
                  onClick={() => finalizeSocialLogin('github')}
                  disabled={isLoading}
                  className="w-full bg-[#238636] hover:bg-[#2ea043] text-white font-bold py-1.5 rounded-md transition-colors border border-[rgba(240,246,252,0.1)] flex items-center justify-center gap-2"
               >
                  {isLoading ? <Loader2 size={16} className="animate-spin" /> : 'Sign in'}
               </button>
            </div>
         </div>

         <div className="mt-8 p-4 border border-[#30363d] rounded-lg text-sm flex gap-2">
            <span>New to GitHub?</span>
            <span className="text-blue-400 hover:underline cursor-pointer">Create an account</span>
         </div>

         <div className="mt-8 text-xs text-gray-500 flex gap-4">
             <span className="hover:text-blue-400 cursor-pointer">Terms</span>
             <span className="hover:text-blue-400 cursor-pointer">Privacy</span>
             <span className="hover:text-blue-400 cursor-pointer">Security</span>
             <button onClick={() => setSocialProvider(null)} className="hover:text-white underline">Cancel Simulation</button>
         </div>
      </div>
    );
  }

  // --- MAIN LOGIN VIEW ---
  return (
    <div className="min-h-[80vh] flex items-center justify-center px-4 relative animate-in fade-in zoom-in duration-500">

      {/* Background Decor */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] bg-primary/20 blur-[100px] rounded-full opacity-20 -z-10 pointer-events-none"></div>

      <div className="w-full max-w-md">
        <div className="ninja-card p-8 relative overflow-hidden">

          {/* Header */}
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl flex items-center justify-center text-white font-bold font-sans text-3xl mx-auto mb-6 shadow-lg shadow-primary/20">
              C
            </div>
            <h1 className="text-2xl font-sans font-bold text-white mb-2">
                {isRegistering ? <>Créer un <span className="gradient-text">compte</span></> : <>Bon <span className="gradient-text">retour</span></>}
            </h1>
            <p className="text-gray-400 text-sm">
                {isRegistering 
                    ? 'Rejoignez la première plateforme AEO.' 
                    : 'Connectez-vous pour accéder à votre dashboard.'}
            </p>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-4">

            {error && (
              <div className="bg-red-500/10 border border-red-500/20 rounded-xl p-3 flex items-start gap-3 text-red-200 text-sm animate-in slide-in-from-top-2">
                <AlertCircle size={18} className="shrink-0 mt-0.5" />
                <span>{error}</span>
              </div>
            )}

            {isRegistering && (
                <div className="space-y-1.5 animate-in slide-in-from-left-2 duration-300">
                <label className="text-sm font-medium text-gray-300 ml-1">Nom complet</label>
                <div className="relative">
                    <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Jean Dupont"
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/50 transition-all outline-none"
                    required={isRegistering}
                    />
                </div>
                </div>
            )}

            <div className="space-y-1.5">
              <label className="text-sm font-medium text-gray-300 ml-1">Email professionnel</label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="nom@entreprise.com"
                  className="w-full bg-[#111111] border border-white/[0.08] rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/50 transition-all outline-none"
                  required
                />
              </div>
            </div>

            <div className="space-y-1.5">
              <div className="flex justify-between items-center ml-1">
                <label className="text-sm font-medium text-gray-300">Mot de passe</label>
                {!isRegistering && (
                    <a href="#" className="text-xs text-primary hover:text-white transition-colors">Oublié ?</a>
                )}
              </div>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full bg-[#111111] border border-white/[0.08] rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/50 transition-all outline-none"
                  required
                />
              </div>
            </div>

            {isRegistering && (
                <div className="space-y-1.5 animate-in slide-in-from-left-2 duration-300">
                <label className="text-sm font-medium text-gray-300 ml-1">Confirmer le mot de passe</label>
                <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                    type="password" 
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    placeholder="••••••••"
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl py-3 pl-10 pr-4 text-white placeholder-gray-600 focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/50 transition-all outline-none"
                    required={isRegistering}
                    />
                </div>
                </div>
            )}

            <button 
              type="submit" 
              disabled={isLoading}
              className="btn-gradient w-full text-white font-bold py-3.5 rounded-full transition-all transform active:scale-95 flex items-center justify-center gap-2 mt-2"
            >
              {isLoading ? <Loader2 size={20} className="animate-spin" /> : <>
                {isRegistering ? 'Créer un compte & Accéder au Dashboard' : 'Se connecter'} <ArrowRight size={18} />
              </>}
            </button>
          </form>

          {/* Social / Divider */}
          <div className="relative my-8">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-white/[0.08]"></div>
            </div>
            <div className="relative flex justify-center text-xs uppercase">
              <span className="bg-[#111111] px-2 text-gray-500">Ou continuer avec</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
             <button 
                type="button" 
                onClick={() => initSocialLogin('google')}
                className="flex items-center justify-center gap-2 py-2.5 border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.07] rounded-full transition-colors text-sm font-medium"
             >
                <svg className="w-4 h-4" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
                Google
             </button>
             <button 
                type="button" 
                onClick={() => initSocialLogin('github')}
                className="flex items-center justify-center gap-2 py-2.5 border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.07] rounded-full transition-colors text-sm font-medium"
             >
                <Github size={16} />
                GitHub
             </button>
          </div>

          <div className="mt-8 text-center">
             <p className="text-gray-400 text-sm">
               {isRegistering ? 'Déjà un compte ?' : 'Pas encore de compte ?'}
               <button onClick={toggleMode} className="text-primary hover:underline ml-1 font-medium">
                 {isRegistering ? 'Se connecter' : "S'inscrire"}
               </button>
             </p>
          </div>

        </div>

        <button onClick={onBack} className="w-full text-center mt-6 text-gray-500 hover:text-white text-sm transition-colors">
           Retour à l'accueil
        </button>
      </div>
    </div>
  );
};

export default Login;"}

